概念和例子防抖函数 (debounce)防抖函数的作用是在一段时间内，不管触发多少次回调，只执行最后一次。比如在输入框输入时，只有在输入完成后，才会触发回调。
// fn 是需要防抖的函数，delay 是防抖的时间function debounce(fn,delay)&#123;    // 定时器    let timer = null;    // 返回一个函数    return function()&#123;        const that = this        // 如果定时器存在，清除定时器        if(timer)&#123;            clearTimeout(timer);        &#125;        // 重新设置定时器        timer = setTimeout(()=&gt;&#123;            // 执行函数            fn.apply(that,arguments);        &#125;,delay);    &#125;&#125;

节流函数 (throttle)节流函数的作用是在一段时间内，不管触发多少次回调，只执行一次。比如在滚动事件中，只有在停止滚动后，才会触发回调。
function throttle(fn,delay)&#123;    // 定时器    let timer = null;    // 返回一个函数    return function()&#123;        // 如果定时器不存在        if(!timer)&#123;            // 设置定时器            timer = setTimeout(()=&gt;&#123;                // 执行函数                fn.apply(this,arguments);                // 清除定时器                timer = null;            &#125;,delay);        &#125;    &#125;&#125;
